import { existsSync, readdirSync, readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const seedPath = join(here, "../../data/pf2e/skill-actions.json");
const generatedDir = join(here, "../../data/pf2e/generated");

/** Unified rule record (generated by `npm run data:pf2e` or from the seed). */
export interface RuleRecord {
  name: string;
  category: string;
  traits?: string[];
  level?: number | null;
  rarity?: string | null;
  text: string;
  source: string;
}

interface SeedAction {
  id: string;
  name: string;
  skill: string;
  summary: string;
  criticalSuccess?: string;
  success?: string;
  failure?: string;
  criticalFailure?: string;
}

let index: RuleRecord[] | null = null;
let byName: Map<string, RuleRecord> | null = null;
let sourceLabel = "seed";

function normalize(s: string): string {
  return s
    .toLowerCase()
    .normalize("NFD")
    .replace(/[̀-ͯ]/g, "")
    .trim();
}

function loadSeed(): RuleRecord[] {
  try {
    const data = JSON.parse(readFileSync(seedPath, "utf8")) as {
      actions: SeedAction[];
    };
    return data.actions.map((a) => ({
      name: a.name,
      category: "actions",
      text: [
        a.summary,
        a.criticalSuccess ? `Critical success: ${a.criticalSuccess}` : "",
        a.success ? `Success: ${a.success}` : "",
        a.failure ? `Failure: ${a.failure}` : "",
        a.criticalFailure ? `Critical failure: ${a.criticalFailure}` : "",
      ]
        .filter(Boolean)
        .join(" "),
      source: "seed",
    }));
  } catch {
    return [];
  }
}

function loadGenerated(): RuleRecord[] {
  const out: RuleRecord[] = [];
  for (const file of readdirSync(generatedDir)) {
    if (!file.endsWith(".json")) continue;
    try {
      const arr = JSON.parse(
        readFileSync(join(generatedDir, file), "utf8"),
      ) as RuleRecord[];
      out.push(...arr);
    } catch {
      // ignore invalid file
    }
  }
  return out;
}

function load(): RuleRecord[] {
  if (index) return index;
  if (existsSync(generatedDir)) {
    index = loadGenerated();
    sourceLabel = `foundry-generated (${index.length} entries)`;
  }
  if (!index || index.length === 0) {
    index = loadSeed();
    sourceLabel = "seed (run `npm run data:pf2e` for the full dataset)";
  }
  byName = new Map();
  for (const r of index) {
    const key = normalize(r.name);
    // Keep the first (avoids overwriting with same-named variants).
    if (!byName.has(key)) byName.set(key, r);
  }
  return index;
}

/**
 * Looks up a rule by name (any category). Strategy: exact name → substring →
 * highest token overlap. Returns the best match or `null`.
 */
export function lookupLocalRule(query: string): RuleRecord | null {
  const all = load();
  const q = normalize(query);
  if (!q) return null;

  // 1. Exact name.
  const exact = byName!.get(q);
  if (exact) return exact;

  // 2. Substring (prefers the shortest name = most specific match).
  let best: RuleRecord | null = null;
  let bestLen = Infinity;
  for (const r of all) {
    const n = normalize(r.name);
    if (n.includes(q) || q.includes(n)) {
      if (n.length < bestLen) {
        best = r;
        bestLen = n.length;
      }
    }
  }
  if (best) return best;

  // 3. Token overlap.
  const qTokens = new Set(q.split(/\s+/).filter((t) => t.length > 2));
  if (qTokens.size === 0) return null;
  let bestScore = 0;
  for (const r of all) {
    const nTokens = normalize(r.name).split(/\s+/);
    let score = 0;
    for (const t of nTokens) if (qTokens.has(t)) score++;
    if (score > bestScore) {
      bestScore = score;
      best = r;
    }
  }
  return bestScore > 0 ? best : null;
}

export function datasetSource(): string {
  load();
  return sourceLabel;
}
